@Composable
private fun CameraBottomDock(
    uiState: ScanSessionUiState,
    onCapture: () -> Unit,
    onRetakePageSelection: (String?) -> Unit,
    modifier: Modifier = Modifier,
) {
    Column(
        modifier = modifier,
        verticalArrangement = Arrangement.spacedBy(12.dp),
    ) {
        Box(modifier = Modifier.fillMaxWidth()) {
            DetectionMeta(
                liveDetection = uiState.liveDetection,
                modifier = Modifier
                    .align(Alignment.CenterStart)
                    .padding(horizontal = 16.dp),
            )
        }
        if (uiState.pages.isNotEmpty()) {
            LazyRow(
                horizontalArrangement = Arrangement.spacedBy(10.dp),
                contentPadding = PaddingValues(horizontal = 16.dp),
            ) {
                items(
                    items = uiState.pages,
                    key = { page -> page.id },
                ) { page ->
                    val selectedForReplacement = uiState.replacementPageId == page.id
                    Surface(
                        modifier = Modifier
                            .size(width = 76.dp, height = 102.dp)
                            .clickable {
                                onRetakePageSelection(
                                    if (selectedForReplacement) null else page.id,
                                )
                            },
                        color = Color.Black.copy(alpha = 0.46f),
                        shape = MaterialTheme.shapes.large,
                        border = BorderStroke(
                            width = if (selectedForReplacement) 2.dp else 1.dp,
                            color = if (selectedForReplacement) {
                                OverlayBlue
                            } else {
                                Color.White.copy(alpha = 0.12f)
                            },
                        ),
                    ) {
                        Column(
                            modifier = Modifier.padding(8.dp),
                            verticalArrangement = Arrangement.spacedBy(6.dp),
                        ) {
                            DocumentThumbnail(
                                thumbnailPath = page.thumbnailPath,
                                title = "Page ${page.pageIndex + 1}",
                                modifier = Modifier.fillMaxWidth(),
                                minHeight = 56.dp,
                            )
                            Text(
                                text = "P${page.pageIndex + 1}",
                                style = MaterialTheme.typography.labelLarge,
                                color = Color.White,
                            )
                        }
                    }
                }
            }
        }
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp)
                .padding(top = 6.dp),
        ) {
            Surface(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(top = 22.dp),
                color = Color.Black.copy(alpha = 0.58f),
                shape = RoundedCornerShape(28.dp),
            ) {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 16.dp, vertical = 16.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.SpaceBetween,
                ) {
                    DockPill(
                        label = if (uiState.captureInProgress) "Saving" else if (uiState.isReplacementMode) "Retake" else "Scan",
                        icon = Icons.Filled.CameraAlt,
                    )
                    SpacerDock()
                    DockPill(
                        label = uiState.liveDetection.compactStatusLabel(),
                    )
                }
            }
            CaptureButton(
                busy = uiState.captureInProgress,
                replacement = uiState.isReplacementMode,
                onClick = onCapture,
                modifier = Modifier.align(Alignment.TopCenter),
            )
        }
    }
}

