private const val RouteTransitionDurationMillis = 280

private fun AnimatedContentTransitionScope<NavBackStackEntry>.slideInForward(): EnterTransition =
    slideIntoContainer(
        towards = AnimatedContentTransitionScope.SlideDirection.Left,
        animationSpec = tween(RouteTransitionDurationMillis),
    ) + fadeIn(animationSpec = tween(RouteTransitionDurationMillis))

private fun AnimatedContentTransitionScope<NavBackStackEntry>.slideOutForward(): ExitTransition =
    slideOutOfContainer(
        towards = AnimatedContentTransitionScope.SlideDirection.Left,
        animationSpec = tween(RouteTransitionDurationMillis),
    ) + fadeOut(animationSpec = tween(RouteTransitionDurationMillis))

private fun AnimatedContentTransitionScope<NavBackStackEntry>.slideInBackward(): EnterTransition =
    slideIntoContainer(
        towards = AnimatedContentTransitionScope.SlideDirection.Right,
        animationSpec = tween(RouteTransitionDurationMillis),
    ) + fadeIn(animationSpec = tween(RouteTransitionDurationMillis))

private fun AnimatedContentTransitionScope<NavBackStackEntry>.slideOutBackward(): ExitTransition =
    slideOutOfContainer(
        towards = AnimatedContentTransitionScope.SlideDirection.Right,
        animationSpec = tween(RouteTransitionDurationMillis),
    ) + fadeOut(animationSpec = tween(RouteTransitionDurationMillis))
